// Return this CPU's cpu struct.
// Interrupts must be disabled.
struct cpu*
mycpu(void)
{
  int id = cpuid();
  struct cpu *c = &cpus[id];

  return c;
}

// Return the current struct proc *, or zero if none.
struct proc*
myproc(void)
{

  push_off();
  struct cpu *c = mycpu();
  // if(!(c->thread)) panic("cpu's thread = null!!\n");
  struct proc *p = c->thread->p;
  pop_off();
  return p;
}

