void
usertrap(void)
{
  int which_dev = 0;
#ifdef __DEBUG_UTRAP
  // walk_va(myproc()->mm.pagetable, THREAD_TRAPFRAME(mythread()->tidx));
  // walk_va(myproc()->mm.pagetable, TRAMPOLINE);
