uint64
sys_dup(void)
{
  struct file *f;
  int fd;

  if(argfd(0, 0, &f) < 0)
    return -1;
  if((fd = fdalloc(f)) < 0)
    return fd;
  filedup(f);
  return fd;
}

/**
 * @brief dup3() duplicates the file descriptor oldfd to newfd, closing newfd first if it was open.
       If flags is specified, it is used to set the close-on-exec flag for newfd.
 * 
 * @property int dup3(int oldfd, int newfd, int flags);
 * @return uint64 
 */
uint64 sys_dup3(void) {
  int oldfd, newfd, flags, ret;
  struct file *f;
  if(argfd(0, &oldfd, &f) < 0)
    return -1;
  argint(1, &newfd);
  argint(2, &flags);
  if(oldfd < 0 || oldfd >= NOFILE || newfd < 0 || newfd >= NOFILE)
    return -1;
#ifdef __DEBUG_SYS_DUP3
  Log("sys_dup3: oldfd=%d, newfd=%d, flags=%d", oldfd, newfd, flags);
#endif
  if(newfd == oldfd) {
    return -EINVAL;
  }
  if((ret = fdalloc_spec(f, newfd)) < 0)
    return ret;
  if (flags & O_CLOEXEC) {
    f->flags |= O_CLOEXEC; // set the close-on-exec flag
  } else {
    f->flags &= ~O_CLOEXEC; // clear the close-on-exec flag
  }
  filedup(f);
  return newfd;
}
/**
 * @brief ssize_t read(int fd, void buf[.count], size_t count);  
 * 
 * read() attempts to read up to count bytes from file descriptor fd
       into the buffer starting at buf.
 * 
 * @return  On success, the number of bytes read is returned (zero indicates
       end of file), and the file position is advanced by this number.
       It is not an error if this number is smaller than the number of
       bytes requested; this may happen for example because fewer bytes
       are actually available right now (maybe because we were close to
       end-of-file, or because we are reading from a pipe, or from a
       terminal), or because read() was interrupted by a signal.  See
       also NOTES.

       On error, -1 is returned, and errno is set to indicate the error.
       In this case, it is left unspecified whether the file position (if
       any) changes.
 */
uint64 sys_read(void)
{
  struct file *f;
  size_t n;
  uint64 p;
  int fd;
  argaddr(1, &p);
  argulong(2, &n);
  if(argfd(0, &fd, &f) < 0)
    return -1;
#ifdef __DEBUG_SYS_READ
  Log("sys_read: fd=%d, p=%p, n=%d, f->pos %d", fd, p, n, f->fpos);
#endif
  return fileread(f, 1, p, n, f->fpos);
}

int generic_readv(struct file *f, uint64 iov, int iovcnt) {
  int rcnt = 0;
  char *kvecs = NULL;
  if((kvecs = kmalloc(sizeof(struct iovec) * iovcnt)) == NULL) {
    printf("generic_readv: kmalloc failed\n");
    return -1;
  }
  if(either_copyin(kvecs, 1, iov, sizeof(struct iovec) * iovcnt) < 0) {
    printf("generic_readv: either_copyin failed\n");
    kfree(kvecs);
    return -1;
  }
  struct iovec *kvec = (struct iovec *)kvecs;
  int rc = 0;
  for(int i = 0; i < iovcnt; i++) {
    if(kvec[i].iov_len <= 0 || kvec[i].iov_base == 0) {
      continue;
    }
    if((rc = fileread(f, 1, (uint64) kvec[i].iov_base, kvec[i].iov_len, f->fpos)) < 0) {
      printf("generic_readv: fileread failed\n");
      goto bad;
    }
    rcnt += rc;
    kvec++;
  }

#ifdef __DEBUG_SYS_READV
  Log("generic_readv: read %d bytes from fd=%d, f->pos=%d", rcnt, f->fd, f->fpos);
#endif

  if(kvecs)
    kfree(kvecs);
  return rcnt;
bad:
  if(kvecs)
    kfree(kvecs);
  return -1;
}
/**
 * @brief  The readv() system call reads iovcnt buffers from the file
       associated with the file descriptor fd into the buffers described
       by iov ("scatter input").
 * @property ssize_t readv(int fd, const struct iovec *iov, int iovcnt);
 * @return on success, return the number of bytes read. -1 on error.
 */
uint64 sys_readv(void) {
  struct file *f;
  int fd, iovcnt;
  uint64 iov;
  int r = 0;

  argaddr(1, &iov);
  argint(2, &iovcnt);
  if(argfd(0, &fd, &f) < 0)
    return -1;
#ifdef __DEBUG_SYS_READV
  Log("sys_readv: fd=%d, iov=%p, iovcnt=%d, f->pos %d", fd, iov, iovcnt, f->fpos);
#endif
  if((r = generic_readv(f, iov, iovcnt)) < 0) {
    printf("sys_readv: generic_readv failed\n");
    return -1;
  }
#ifdef __DEBUG_SYS_READV
  Log("sys_readv: read %d bytes", r);
#endif
  return r;
}

